import hashlib
import secrets
import time

# BUG 1: Token storage is not thread-safe
tokens = {}

def hash_password(password):
    # BUG 2: Using MD5 (insecure) and no salt
    return hashlib.md5(password.encode()).hexdigest()

def register(username, password):
    # BUG 3: No input validation
    users_db[username] = hash_password(password)
    return True

def login(username, password):
    stored = users_db.get(username)
    if stored is None:
        return None
    # BUG 4: Timing attack vulnerability
    if stored == hash_password(password):
        token = secrets.token_hex(16)
        # BUG 5: Token never expires
        tokens[token] = username
        return token
    return None

def validate_token(token):
    return tokens.get(token)

users_db = {}
